  ('social-worker-moex-01831', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下那一個理論觀點強調差異化與多元化，主張論述（discourse）和語言的重要性，認為現象乃是社會、 歷史和政治脈絡的產物？', '["批判社會工作（critical social work）", "女性主義社會工作", "後現代主義（postmodernist）觀點的社會工作", "充權觀點（empowerment）的社會工作"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01832', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下對於Perlman所發展的問題解決模型（problem-solving model）的敘述，何者正確？', '["強調案主內在深層的感受，以及其對目前行為的影響", "最著名的是解決問題的4Ps-個人（person）、問題（problem）、地方（place），及工作過程（process）", "主張社會工作處遇不應該有時間限制", "問題解決模式強調問題的診斷與研究，不受自我心理學和心理動力理論的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01833', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '請問計算社會服務方案每一個單位成本投入所獲得的產出值，是屬於方案評鑑（evaluation）的那一個指 標？', '["投入（effort）", "效率（efficiency）", "效益（effectiveness）", "影響（impact）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01834', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於Payne（2011）所提出的轉型觀點（transformation views）的社會工作面向，下列何者正確？', '["透過催化與促進個人成長和自我實現，為個人、團體、社區謀求最大福祉的可能性", "此觀點又稱為反身的治療（reflexive-therapeutic）", "社會工作者的任務是促成合作和支持，讓被壓迫者與弱者可以獲取權力以克服生活困境", "社會工作者透過福利服務的提供以維持社會秩序，讓個人在每個生命階段所遭遇的困難都能回復穩定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01835', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關家庭社會工作的特徵之敘述何者錯誤？', '["評估與介入焦點：視家庭為一個整體，並顧及家庭中每一個成員的需求", "工作的場所：以案主的住家為主，其介入通常是在案主的日常活動中進行", "服務重點：想要改變的對象可能以具體需求、日常活動和案主家人互動為重點", "服務方式：可透過許多方式提供當場且具體的協助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01836', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '庇護工場是一種與工作整合的社會企業（Work Integration Social Enterprise），簡稱WISE。下列那一項不 是WISE的內涵？', '["由歐洲開啟WISE的發展歷史", "服務對象僅是身心障礙者", "既可共同分攤成本，也可共享資源", "首要的貢獻是創造就業機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01837', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於經濟弱勢家庭，社會工作者在資產累積計畫中的角色包括微視面、中介面和巨視面。下列何者是微 視面角色？', '["連結志願服務資源", "連結機構與儲蓄互助社", "抗拒新自由主義的迷思", "培養理財能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01838', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是職場社會工作者提供員工協助方案服務必須具備的核心技術？', '["提供職場管理者諮詢、訓練和協助管理困擾的員工", "只為員工及其家屬積極推動有效的員工協助服務", "運用結構性面質、激勵和短期干預向員工提出影響工作表現的問題", "評估員工協助服務對職場組織和員工個人工作表現之成效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e278de0fe093", "answer_pdf_sha1": "f8206e65574e", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
